import{_ as e,c as t,o as a,aR as o}from"./chunks/framework.C7RrxATG.js";const b=JSON.parse('{"title":"AI","description":"","frontmatter":{"version":"New"},"headers":[],"relativePath":"en-US/guide/ai.md","filePath":"en-US/guide/ai.md","lastUpdated":1776153999000}'),r={name:"en-US/guide/ai.md"},s=o('<h1 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h1><p>Wot UI is an AI-friendly component library. This guide aims to introduce how to help AI tools like VSCode, Cursor, TRAE, and Antigravity better understand the Wot UI component library.</p><h2 id="llms-txt" tabindex="-1">llms.txt <a class="header-anchor" href="#llms-txt" aria-label="Permalink to &quot;llms.txt&quot;">​</a></h2><p><a href="https://llmstxt.org/" target="_blank" rel="noreferrer">llms.txt</a> is a text file designed for Large Language Models (LLMs), similar to robots.txt but with a different purpose. While robots.txt tells search engine crawlers which pages can be crawled, llms.txt provides structured information about website content for AI tools, helping them better understand and index the site. The &quot;llms&quot; in the name stands for &quot;Large Language Models&quot;. It contains key documentation links, code examples, and best practices for the project, enabling AI tools like VSCode, Cursor, TRAE, and Antigravity to better comprehend the Wot UI component library.</p><h3 id="available-resources" tabindex="-1">Available Resources <a class="header-anchor" href="#available-resources" aria-label="Permalink to &quot;Available Resources&quot;">​</a></h3><p>We provide 2 llms.txt routes to help AI tools access documentation:</p><ul><li><a href="https://wot-ui.cn/llms.txt" target="_blank" rel="noreferrer">llms.txt</a> - A structured overview containing all components and their documentation links</li><li><a href="https://wot-ui.cn/llms-full.txt" target="_blank" rel="noreferrer">llms-full.txt</a> - Full documentation including implementation details and examples</li></ul><h3 id="usage-in-ai-tools" tabindex="-1">Usage in AI Tools <a class="header-anchor" href="#usage-in-ai-tools" aria-label="Permalink to &quot;Usage in AI Tools&quot;">​</a></h3><h4 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h4><p>Find the <code>Indexing &amp; Docs</code> setting in Cursor, and add <code>llms.txt</code> to <code>Docs</code>. Use the <code>@Docs</code> feature to include the llms.txt file in your project.</p><p><a href="https://cursor.com/docs/agent/tools/search" target="_blank" rel="noreferrer">Learn more about @Docs in Cursor</a></p><h4 id="trae" tabindex="-1">TRAE <a class="header-anchor" href="#trae" aria-label="Permalink to &quot;TRAE&quot;">​</a></h4><p>Find the <code>Context/Documentation</code> setting in TRAE, and add <code>llms.txt</code> to <code>Documentation</code>. Use the <code>#Docs</code> feature to include the llms.txt file in your project.</p><p><a href="https://docs.trae.ai/ide/number-sign" target="_blank" rel="noreferrer">Learn more about #Docs in TRAE</a></p><h4 id="other-tools" tabindex="-1">Other Tools <a class="header-anchor" href="#other-tools" aria-label="Permalink to &quot;Other Tools&quot;">​</a></h4><p>Any tool that supports the <code>llms.txt</code> standard or can ingest documentation from a URL can use the <code>llms.txt</code> file we provide. You can add the <code>llms.txt</code> file to your tool&#39;s <code>Documentation</code> or <code>rules</code> to help the AI tool better understand the Wot UI component library.</p><h4 id="context7" tabindex="-1">context7 <a class="header-anchor" href="#context7" aria-label="Permalink to &quot;context7&quot;">​</a></h4><p>Even without using <code>llms.txt</code>, you can use <a href="https://github.com/upstash/context7" target="_blank" rel="noreferrer">context7</a> to directly read the component library documentation.</p><p><a href="https://github.com/upstash/context7" target="_blank" rel="noreferrer">Learn more about context7</a></p><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h2><p>Skills are &quot;superpower templates&quot; for AI, a complete, reusable set of solutions for specific problems. Wot UI also provides some predefined <a href="https://skills.sh/?q=wot-ui" target="_blank" rel="noreferrer">Skills</a> that you can use directly in AI.</p><h3 id="available-resources-1" tabindex="-1">Available Resources <a class="header-anchor" href="#available-resources-1" aria-label="Permalink to &quot;Available Resources&quot;">​</a></h3><ul><li><a href="https://skills.sh/?q=wot-ui" target="_blank" rel="noreferrer">skills.sh</a> - An open Agent Skills ecosystem collecting countless skills, including those related to Wot UI.</li><li><a href="https://starter.wot-ui.cn/guide/skills.html" target="_blank" rel="noreferrer">wot-starter</a> - A quick start template provided by Wot UI, containing Wot UI related skills.</li></ul><h3 id="usage-in-ai-tools-1" tabindex="-1">Usage in AI Tools <a class="header-anchor" href="#usage-in-ai-tools-1" aria-label="Permalink to &quot;Usage in AI Tools&quot;">​</a></h3><p>We recommend installing Skills using a script. You can choose installation options based on your needs:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/wot-ui/wot-starter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wot-ui</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://juejin.cn/post/7500981295105015847" target="_blank" rel="noreferrer">llms.txt: Let AI better understand your documentation</a></li><li><a href="https://juejin.cn/post/7599268297201958950" target="_blank" rel="noreferrer">Agent Skills, Rules, Prompt, MCP: Clearing them all up in one article</a></li></ul>',28),l=[s];function i(n,c,d,h,u,p){return a(),t("div",null,l)}const g=e(r,[["render",i]]);export{b as __pageData,g as default};
